import subprocess
import os

def convertDocument(input_file, output_file, output_format):
    if not input_file.endswith(('.docx', '.odt', '.txt')):
        raise ValueError("Unsupported input file format")
    
    if not output_file.endswith(('.pdf', '.jpg', '.png', '.docx', '.odt')):
        raise ValueError("Unsupported output file format")

    # Set LibreOffice path
    libreoffice_path = 'C:/Program Files/LibreOffice/program/libreoffice.exe'  # adjust to your system

    # Create command for conversion
    if output_format == 'pdf':
        cmd = f'{libreoffice_path} --headless --convert-to pdf "{input_file}" --outdir .'
    elif output_format == 'jpg' or output_format == 'png':
        cmd = f'{libreoffice_path} --headless --export-drawable-as png "{input_file}" --outdir .'
    elif output_format == 'docx':
        cmd = f'{libreoffice_path} --headless --convert-to docx "{input_file}" --outdir .'
    else:
        raise ValueError("Unsupported output format")

    # Execute command
    try:
        subprocess.run(cmd, shell=True, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Conversion failed: {e}")
        return False

    # Move converted file to specified location
    if os.path.exists(output_file):
        os.remove(output_file)
    os.rename(input_file.replace('.pdf', '').replace('.jpg', '').replace('.png', ''), output_file)

    return True